def determine_winner(ohio_state_score, tennessee_score):
    if ohio_state_score > tennessee_score:
        return "Ohio State Buckeyes"
    elif tennessee_score > ohio_state_score:
        return "Tennessee Volunteers"
    else:
        return "Tie"

# Example usage:
print(determine_winner(20, 19))  # Output: Ohio State Buckeyes
